"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[601442],{557024:e=>{e.exports=JSON.parse('{"tag":{"label":"persistence","permalink":"/dst-api-webdocs/docs/tags/persistence","allTagsPath":"/dst-api-webdocs/docs/tags","count":33,"items":[{"id":"game-scripts/components/abysspillargroup","title":"Abysspillargroup","description":"Manages a group of abyss pillars, tracking their lifecycle, spawn points, and synchronization during save/load operations.","permalink":"/dst-api-webdocs/docs/game-scripts/components/abysspillargroup"},{"id":"game-scripts/prefabs/archive_pillar","title":"Archive Pillar","description":"Represents a decorative, non-interactive archive pillar prop that can exist in intact or broken states, with state persistence across saves and network synchronization.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/archive_pillar"},{"id":"game-scripts/components/attunable","title":"Attunable","description":"Manages attunement relationships between an entity and players, supporting online/offline tracking and networked persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/components/attunable"},{"id":"game-scripts/components/bundler","title":"Bundler","description":"Manages the bundling workflow for items, including spawning bundling containers, wrapping items, and persisting state across saves.","permalink":"/dst-api-webdocs/docs/game-scripts/components/bundler"},{"id":"game-scripts/prefabs/burntground","title":"Burntground","description":"Manages the animated, fading visual effect of burnt ground patches, including network synchronization and persistence across saves.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/burntground"},{"id":"game-scripts/prefabs/corpses","title":"Corpses","description":"Manages the lifecycle, mutation, looting, and decay of creature corpses, including handling lunar rift mutations and gestalt possession.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/corpses"},{"id":"game-scripts/components/deathloothandler","title":"Deathloothandler","description":"Stores and persists loot information associated with an entity\'s death, such as item prefabs and an optional level value.","permalink":"/dst-api-webdocs/docs/game-scripts/components/deathloothandler"},{"id":"game-scripts/components/debuffable","title":"Debuffable","description":"Manages application, tracking, and removal of debuff effects on an entity, including persistence across save/load cycles and entity transfers.","permalink":"/dst-api-webdocs/docs/game-scripts/components/debuffable"},{"id":"game-scripts/components/dryingrack","title":"Dryingrack","description":"Manages drying behavior for items placed in a container, handling time-based drying, weather effects (rain/acid rain), and state persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/components/dryingrack"},{"id":"game-scripts/prefabs/farm_soil","title":"Farm Soil","description":"Represents tilled soil in the farm, handling visual states, plowing state tracking, and persistence across saves.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/farm_soil"},{"id":"game-scripts/components/followermemory","title":"Followermemory","description":"Remembers and tracks a follower\'s last known leader across sessions and entity state changes, enabling reunification when the leader returns.","permalink":"/dst-api-webdocs/docs/game-scripts/components/followermemory"},{"id":"game-scripts/components/ghostbabysitter","title":"Ghostbabysitter","description":"Manages the tracking and lifecycle of ghosts being watched over by an entity, handling state tags and persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/components/ghostbabysitter"},{"id":"game-scripts/prefabs/ghostvision_buff","title":"Ghostvision Buff","description":"Applies a networked night vision effect to players by manipulating lighting and colour correction, while managing buff lifetime and persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ghostvision_buff"},{"id":"game-scripts/map/graphedge","title":"Graphedge","description":"Represents a bidirectional connection between two graph nodes in the world map, managing rendering, locking, and data persistence for map navigation structures.","permalink":"/dst-api-webdocs/docs/game-scripts/map/graphedge"},{"id":"game-scripts/components/groundcreep","title":"Groundcreep","description":"Enables serialization and deserialization of a ground creep object attached to an entity, primarily for world persistence across sessions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/groundcreep"},{"id":"game-scripts/components/hideandseekhidingspot","title":"Hideandseekhidingspot","description":"Manages the logic for a location where a Hider entity can be concealed, including spawn, eviction, and cleanup.","permalink":"/dst-api-webdocs/docs/game-scripts/components/hideandseekhidingspot"},{"id":"game-scripts/components/itemstore","title":"Itemstore","description":"Manages a storage list of item records for an entity, supporting adding, retrieving, saving, and loading of items without persisting the actual item instances.","permalink":"/dst-api-webdocs/docs/game-scripts/components/itemstore"},{"id":"game-scripts/components/knowndynamiclocations","title":"Knowndynamiclocations","description":"Manages named dynamic positions associated with an entity, supporting platform-relative storage and persistence across saves.","permalink":"/dst-api-webdocs/docs/game-scripts/components/knowndynamiclocations"},{"id":"game-scripts/components/knownlocations","title":"Knownlocations","description":"Manages a collection of named coordinate positions associated with an entity for persistent tracking and recall.","permalink":"/dst-api-webdocs/docs/game-scripts/components/knownlocations"},{"id":"game-scripts/components/madsciencelab","title":"Madsciencelab","description":"Manages a multi-stage lab-based science-generating process with stage timing and persistence support.","permalink":"/dst-api-webdocs/docs/game-scripts/components/madsciencelab"},{"id":"game-scripts/components/maprecorder","title":"Maprecorder","description":"Stores and manages recorded map data for teaching exploration progress between players.","permalink":"/dst-api-webdocs/docs/game-scripts/components/maprecorder"},{"id":"game-scripts/components/objectspawner","title":"Objectspawner","description":"Manages a collection of spawned prefabs as owned objects, tracking them for persistence and event handling.","permalink":"/dst-api-webdocs/docs/game-scripts/components/objectspawner"},{"id":"game-scripts/components/possessedaxe","title":"Possessedaxe","description":"Manages the transformation and reversion logic for Lucy, a possessed axe that links to a woodcutter player and reverts to a standard axe under specific conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/possessedaxe"},{"id":"game-scripts/components/pumpkincarvable","title":"Pumpkincarvable","description":"Manages carving, visual rendering, and state persistence of pumpkins in the game, including cut shapes, lighting effects, and synchronization between client and server.","permalink":"/dst-api-webdocs/docs/game-scripts/components/pumpkincarvable"},{"id":"game-scripts/util/savedata","title":"Savedata","description":"Base utility class for loading, saving, and erasing persistent player or world data to disk using TheSim\'s API.","permalink":"/dst-api-webdocs/docs/game-scripts/util/savedata"},{"id":"game-scripts/components/snowmandecoratable","title":"Snowmandecoratable","description":"Manages snowman decoration, stacking, hat placement, and state persistence for snowman entities in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/components/snowmandecoratable"},{"id":"game-scripts/components/spawner","title":"Spawner","description":"Manages a single persistent entity (e.g., a named NPC) by spawning, housing, and releasing it according to configured timing and occupancy rules.","permalink":"/dst-api-webdocs/docs/game-scripts/components/spawner"},{"id":"game-scripts/prefabs/trophyscale_fish","title":"Trophyscale Fish","description":"A weighable fish stand that holds and displays caught trophy fish, supports building/removal via actions, and handles item persistence across reloads and burn states.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/trophyscale_fish"},{"id":"game-scripts/components/unwrappable","title":"Unwrappable","description":"Manages the ability for an entity (such as a bundle or gift box) to be unwrapped, storing wrapped items and defining behavior during unwrap actions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/unwrappable"},{"id":"game-scripts/prefabs/vault_pillar","title":"Vault Pillar","description":"Provides a decorative, interactive vault pillar entity with broken/capped states, optional relic attachment, and save/load persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/vault_pillar"},{"id":"game-scripts/components/vaulttorchgrid","title":"Vaulttorchgrid","description":"Manages a grid of vault torch entities and their state persistence in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/vaulttorchgrid"},{"id":"game-scripts/components/worldsettingstimer","title":"Worldsettingstimer","description":"Manages named, resumable, and persistent timers for world-scale settings or events.","permalink":"/dst-api-webdocs/docs/game-scripts/components/worldsettingstimer"},{"id":"game-scripts/prefabs/yot_catcoonshrine","title":"Yot Catcoonshrine","description":"Acts as a special\u796d\u575b that holds a birdfeather offering and becomes a prototyper once activated; supports burning, hammering, and state persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yot_catcoonshrine"}],"unlisted":false}}')}}]);